fn solve(weight: Vec<i64>) -> i64 {
    let n = weight.len();
    if n < 2 {
        return 0;
    }

    let mut stack = Vec::new();
    let mut count = 0;
    let mut last_max = i64::MIN;

    for &w in weight.iter() {
        while let Some(&top) = stack.last() {
            if top < w {
                last_max = top;
                stack.pop();
            } else {
                break;
            }
        }
        if !stack.is_empty() && w < *stack.last().unwrap() {
            count += 1;
            last_max = stack.pop().unwrap();
        }
        stack.push(w);
    }

    count
}
